# BEST PRACTICE: Template-based with validation
class CricketScorePrompt:
    template = """Analyze this cricket match performance:
    Player: {batter_name}
    Runs: {runs_scored}
    Balls: {balls_faced}

    Calculate strike rate and classify form as: Excellent (SR>150), Good (SR 100-150), Average (SR<100)."""

    def format_prompt(self, batter_name: str, runs: int, balls: int) -> str:
        if not all([batter_name, isinstance(runs, int), isinstance(balls, int)]):
            raise ValueError("Invalid inputs")
        return self.template.format(batter_name_name=batter_name, runs_scored=runs, balls_faced=balls)

# ANTI-PATTERN: Unvalidated string concatenation
class BadCricketPrompt:
    def format_prompt(self, batter_name, runs, balls):
        return f"""Analyze this cricket match performance:
        Player: {batter_name}
        Runs: {runs}
        Balls: {balls}
        Please also tell me about {batter_name}'s childhood and career trajectory and random facts."""
        # ❌ Prone to prompt injection, no input validation, bloated unnecessary context

# BEST PRACTICE: Clear instruction with role definition
BEST = """You are a cricket analyst. Classify player form (Excellent/Good/Average) based ONLY on:
1. Strike rate calculation
2. Run distribution
Ignore: player age, team, personal history, weather conditions."""

# ANTI-PATTERN: Vague, open-ended
BAD = """Tell me about this cricket player's performance and anything else interesting about them."""
